-- Sample Order data for User Story 1 (Check Order Status) — data-model.md
-- "Order". Column names are quoted because EF Core's migration
-- (backend/src/AiShoppingAssistant.Infrastructure/Migrations/*_AddOrder.cs)
-- created them in PascalCase; unquoted identifiers would be folded to
-- lowercase by Postgres and would not match.
--
-- Covers every AiShoppingAssistant.Core.Entities.OrderStatus value
-- (InTransit, Delivered, Delayed, Returned) across two sample customers so
-- FR-010's ownership filter (order id + customer id) has a same-order,
-- different-customer case to exercise (order 12345 belongs to cust-1001,
-- NOT cust-1002).
INSERT INTO orders ("OrderId", "CustomerId", "ProductName", "OrderDate", "DeliveryDate", "Status", "Amount")
