-- Sample KnowledgeDocument data for User Story 2 (Policy/Product Search) —
-- data-model.md "KnowledgeDocument". Column names are quoted for the same
-- PascalCase reason as the orders seed above.
--
-- Embeddings below are real 'codemie-text-embedding-ada-002' vectors
-- (1536-dim), computed once via the live CodeMie embedding endpoint against
-- the exact Content text in each row, and Content itself is written in an
-- Allegro.pl/Amazon.pl-style voice (EU 14-day statutory withdrawal right,
-- Smart Returns extended window, rekojmia vs gwarancja warranty distinction).
INSERT INTO knowledge_documents ("DocumentId", "DocumentType", "Title", "Content", "Embedding")
